class OrderService {
  complete(order: Order): void {
    this.repo.save(order);
    this.email.send(order.userId);
    this.analytics.track('order_complete', order.id);
    this.loyalty.addPoints(order.userId, order.total);
    this.webhook.push(order.id);
  }
}

class PaymentService {
  onSuccess(payment: Payment): void {
    this.receipts.send(payment.userId);
    this.metrics.count('payment_success');
    this.audit.log(payment.id);
  }
}

// Version A
class ProfileService {
  update(p: Profile): void {
    this.repo.save(p);
    this.search.reindex(p.id);
    this.analytics.track('profile_updated', p.id);
    this.mail.sendProfileUpdated(p.userId);
  }
}
// Version B
class ProfileService {
  constructor(private bus: EventBus) {}
  update(p: Profile): void {
    this.repo.save(p);
    this.bus.publish('profile_updated', { profileId: p.id, userId: p.userId });
  }
}
